import React, { useState, useEffect } from 'react';
import { View, Text, StyleSheet, TouchableOpacity, SafeAreaView, Dimensions, ActivityIndicator, Alert } from 'react-native';
import MapView, { Marker, PROVIDER_GOOGLE, Polyline } from 'react-native-maps';
import * as Location from 'expo-location';
import axios from 'axios';
import { API_BASE_URL } from './src/constants';

const { width, height } = Dimensions.get('window');

// Coordenadas de lugares populares de Valencia
const VALENCIA_PLACES = {
  'plaza ayuntamiento': { lat: 39.4699, lon: -0.3763 },
  'ciudad de las ciencias': { lat: 39.4544, lon: -0.3507 },
  'estacion del norte': { lat: 39.4668, lon: -0.3774 },
  'jardin del turia': { lat: 39.4730, lon: -0.3700 },
  'playa malvarrosa': { lat: 39.4794, lon: -0.3233 },
  'bioparc': { lat: 39.4797, lon: -0.4057 },
  'mestalla': { lat: 39.4746, lon: -0.3584 },
};

type TransportMode = 'walking' | 'bicycle' | 'scooter' | 'skateboard';
type RoutePreference = 'eco_fast' | 'leisure';

const TRANSPORT_ICONS: Record<TransportMode, string> = {
  walking: '🚶',
  bicycle: '🚲',
  scooter: '🛴',
  skateboard: '🛹',
};

const TRANSPORT_LABELS: Record<TransportMode, string> = {
  walking: 'Andando',
  bicycle: 'Bicicleta',
  scooter: 'Patinete',
  skateboard: 'Monopatín',
};

export default function App() {
  const [userLocation, setUserLocation] = useState<any>(null);
  const [origin, setOrigin] = useState<any>(null);
  const [destination, setDestination] = useState<any>(null);
  const [transportMode, setTransportMode] = useState<TransportMode>('bicycle');
  const [preference, setPreference] = useState<RoutePreference>('eco_fast');
  const [route, setRoute] = useState<any>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [selectingOrigin, setSelectingOrigin] = useState(true);
  const [searchText, setSearchText] = useState('');
  const [showResults, setShowResults] = useState(false);
  const [showTransportSelector, setShowTransportSelector] = useState(false);

  useEffect(() => {
    getLocation();
  }, []);

  const getLocation = async () => {
    try {
      const { status } = await Location.requestForegroundPermissionsAsync();
      if (status !== 'granted') {
        Alert.alert('Permiso denegado', 'No se puede acceder a tu ubicación');
        return;
      }
      const location = await Location.getCurrentPositionAsync({});
      const loc = {
        latitude: location.coords.latitude,
        longitude: location.coords.longitude,
      };
      setUserLocation(loc);
      setOrigin(loc);
    } catch (e) {
      console.error('Error obteniendo ubicación:', e);
    }
  };

  const handleMapPress = (e: any) => {
    const coord = e.nativeEvent.coordinate;
    if (selectingOrigin) {
      setOrigin(coord);
      setSelectingOrigin(false);
    } else {
      setDestination(coord);
    }
  };

  const searchPlace = (text: string) => {
    const lower = text.toLowerCase();
    for (const [name, coords] of Object.entries(VALENCIA_PLACES)) {
      if (name.includes(lower)) {
        if (selectingOrigin) {
          setOrigin(coords);
          setSelectingOrigin(false);
        } else {
          setDestination(coords);
        }
        setSearchText('');
        return;
      }
    }
    Alert.alert('Lugar no encontrado', 'Prueba: Plaza Ayuntamiento, Ciudad de las Ciencias, Estación del Norte...');
  };

  const calculateRoute = async () => {
    if (!origin || !destination) {
      Alert.alert('Atención', 'Selecciona origen y destino en el mapa');
      return;
    }

    setLoading(true);
    setError(null);
    setShowResults(false);

    try {
      const res = await axios.post(API_BASE_URL + '/api/v1/routes', {
        origin: { lat: origin.latitude, lon: origin.longitude },
        destination: { lat: destination.latitude, lon: destination.longitude },
        transport_mode: transportMode,
        preference: preference,
      });

      if (res.data && res.data.length > 0) {
        setRoute(res.data[0]);
        setShowResults(true);
      }
    } catch (e: any) {
      setError(e.message || 'Error al calcular la ruta');
    } finally {
      setLoading(false);
    }
  };

  const resetRoute = () => {
    setRoute(null);
    setShowResults(false);
    setOrigin(userLocation);
    setDestination(null);
    setSelectingOrigin(true);
    setError(null);
  };

  return (
    <SafeAreaView style={styles.container}>
      {/* MAPA SIEMPRE DE FONDO */}
      <MapView
        style={styles.map}
        provider={PROVIDER_GOOGLE}
        initialRegion={{
          latitude: 39.4699,
          longitude: -0.3763,
          latitudeDelta: 0.05,
          longitudeDelta: 0.05,
        }}
        onPress={handleMapPress}
        showsUserLocation
      >
        {origin && (
          <Marker coordinate={origin} pinColor="#2ecc71" title="Origen" />
        )}
        {destination && (
          <Marker coordinate={destination} pinColor="#e74c3c" title="Destino" />
        )}
        {route && (
          <Polyline
            coordinates={[
              { latitude: origin.latitude, longitude: origin.longitude },
              { latitude: destination.latitude, longitude: destination.longitude },
            ]}
            strokeColor="#2ecc71"
            strokeWidth={4}
          />
        )}
      </MapView>

      {/* BARRA SUPERIOR */}
      <View style={styles.topBar}>
        <View style={styles.searchContainer}>
          <Text style={styles.searchIcon}>
            {selectingOrigin ? '🟢' : '🔴'}
          </Text>
          <Text style={styles.searchLabel}>
            {selectingOrigin ? 'Selecciona ORIGEN' : 'Selecciona DESTINO'}
          </Text>
        </View>

        {/* BÚSQUEDA POR NOMBRE */}
        <View style={styles.searchRow}>
          <TouchableOpacity
            style={styles.searchInput}
            onPress={() => {
              Alert.prompt
                ? Alert.prompt(
                    'Buscar lugar',
                    'Ej: plaza ayuntamiento',
                    (text: string) => text && searchPlace(text)
                  )
                : null;
            }}
          >
            <Text style={styles.searchPlaceholder}>🔍 Buscar lugar...</Text>
          </TouchableOpacity>
          <TouchableOpacity style={styles.locateButton} onPress={getLocation}>
            <Text style={styles.locateIcon}>📍</Text>
          </TouchableOpacity>
        </View>
      </View>

      {/* SELECTOR DE TRANSPORTE (flotante izquierda) */}
      <View style={styles.transportPanel}>
        {(['walking', 'bicycle', 'scooter', 'skateboard'] as TransportMode[]).map((mode) => (
          <TouchableOpacity
            key={mode}
            style={[
              styles.transportButton,
              transportMode === mode && styles.transportButtonActive,
            ]}
            onPress={() => setTransportMode(mode)}
          >
            <Text style={styles.transportIcon}>{TRANSPORT_ICONS[mode]}</Text>
            {transportMode === mode && (
              <Text style={styles.transportLabel}>{TRANSPORT_LABELS[mode]}</Text>
            )}
          </TouchableOpacity>
        ))}
      </View>

      {/* SELECTOR DE PREFERENCIA */}
      <View style={styles.preferencePanel}>
        <TouchableOpacity
          style={[
            styles.prefButton,
            preference === 'eco_fast' && styles.prefButtonActive,
          ]}
          onPress={() => setPreference('eco_fast')}
        >
          <Text style={styles.prefIcon}>⚡</Text>
          <Text style={[styles.prefLabel, preference === 'eco_fast' && styles.prefLabelActive]}>
            ECO-Rápida
          </Text>
        </TouchableOpacity>
        <TouchableOpacity
          style={[
            styles.prefButton,
            preference === 'leisure' && styles.prefButtonActive,
          ]}
          onPress={() => setPreference('leisure')}
        >
          <Text style={styles.prefIcon}>🌸</Text>
          <Text style={[styles.prefLabel, preference === 'leisure' && styles.prefLabelActive]}>
            Paseo
          </Text>
        </TouchableOpacity>
      </View>

      {/* BOTÓN CALCULAR */}
      {!showResults && (
        <TouchableOpacity
          style={[styles.calculateButton, (!origin || !destination) && styles.calculateButtonDisabled]}
          onPress={calculateRoute}
          disabled={!origin || !destination || loading}
        >
          {loading ? (
            <ActivityIndicator color="#fff" />
          ) : (
            <Text style={styles.calculateText}>
              🚀 Calcular Ruta Eco
            </Text>
          )}
        </TouchableOpacity>
      )}

      {/* PANEL DE RESULTADOS */}
      {showResults && route && (
        <View style={styles.resultsPanel}>
          <TouchableOpacity style={styles.closeButton} onPress={resetRoute}>
            <Text style={styles.closeText}>✕</Text>
          </TouchableOpacity>

          <Text style={styles.resultTitle}>
            {TRANSPORT_ICONS[transportMode]} Ruta {TRANSPORT_LABELS[transportMode]}
          </Text>

          <View style={styles.resultGrid}>
            <View style={styles.resultItem}>
              <Text style={styles.resultIcon}>📏</Text>
              <Text style={styles.resultValue}>{route.total_distance_km} km</Text>
              <Text style={styles.resultDesc}>Distancia</Text>
            </View>
            <View style={styles.resultItem}>
              <Text style={styles.resultIcon}>⏱️</Text>
              <Text style={styles.resultValue}>{route.total_duration_min} min</Text>
              <Text style={styles.resultDesc}>Duración</Text>
            </View>
            <View style={styles.resultItem}>
              <Text style={styles.resultIcon}>🌍</Text>
              <Text style={styles.resultValue}>{route.co2_saved_kg} kg</Text>
              <Text style={styles.resultDesc}>CO₂ ahorrado</Text>
            </View>
            <View style={styles.resultItem}>
              <Text style={styles.resultIcon}>💨</Text>
              <Text style={[
                styles.resultValue,
                { color: route.avg_air_quality_index <= 2 ? '#2ecc71' : route.avg_air_quality_index <= 3 ? '#f39c12' : '#e74c3c' }
              ]}>
                {route.avg_air_quality_index}/5
              </Text>
              <Text style={styles.resultDesc}>Calidad aire</Text>
            </View>
            <View style={styles.resultItem}>
              <Text style={styles.resultIcon}>🌳</Text>
              <Text style={styles.resultValue}>{(route.green_percentage * 100).toFixed(0)}%</Text>
              <Text style={styles.resultDesc}>Zonas verdes</Text>
            </View>
          </View>

          <TouchableOpacity style={styles.newRouteButton} onPress={resetRoute}>
            <Text style={styles.newRouteText}>🔄 Nueva Ruta</Text>
          </TouchableOpacity>
        </View>
      )}

      {/* ERROR */}
      {error && (
        <View style={styles.errorPanel}>
          <Text style={styles.errorText}>❌ {error}</Text>
          <TouchableOpacity onPress={() => setError(null)}>
            <Text style={styles.errorClose}>✕</Text>
          </TouchableOpacity>
        </View>
      )}
    </SafeAreaView>
  );
}

